const orderDetails = $json;
const storeId = orderDetails.store_id;

// Improved escape function for MarkdownV2
function escapeMarkdownV2(text) {
  const str = String(text || '');
  return str
    .replace(/\\/g, '\\\\')
    .replace(/([_*[\]()~`>#+\-=|{}.!])/g, '\\$1');
}

// Format each item line, escaping everything except the quantity and unit
const itemLines = (orderDetails.items_in_final_order || []).map(item => {
  const unit = item.unit ? ` ${escapeMarkdownV2(item.unit)}` : '';
  return `${escapeMarkdownV2('•')} ${escapeMarkdownV2(item.quantity)}x ${escapeMarkdownV2(item.original_name)}${unit}`;
}).join('\n');

// Build the message with consistent formatting and full escaping
const message =
  `🔔 *${escapeMarkdownV2('New Paid Order!')}* 🔔\n\n` +
  `*${escapeMarkdownV2('Order ID:')}* \\#${escapeMarkdownV2(orderDetails.order_id)}\n\n` +
  `${escapeMarkdownV2('Please pack the following items:')}\n\n` +
  `${itemLines}\n\n` +
  `*${escapeMarkdownV2('Delivery Address:')}*\n` +
  `${escapeMarkdownV2(orderDetails.address)}\n\n` +
  `${escapeMarkdownV2('Please prepare the order for pickup.')}`;

return [{
  json: {
    message_to_send: message,
    store_id_to_notify: storeId,
    parse_mode: 'MarkdownV2'
  }
}];
